  const salt = crypto.randomBytes(16).toString('base64');
  const iterations = parseInt(PASSWORD_ITERATIONS, 10);
  const keylen = parseInt(PASSWORD_KEYLEN, 10);
  const digest = PASSWORD_DIGEST;

